108→    proc.stderr.on('data', (data) => { stderr += data.toString() })
109→
110→    proc.on('close', (code) => {
111→      resolve({ stdout, stderr, code: code ?? 1 })
112→    })
113→
114→    proc.on('error', (err) => {
