174→        if (check?.ok) { daemonReady = true; break }
175→      }
176→    }
177→
178→    // 4. Migrate each task to kspec
179→    let migrated = 0
180→    if (daemonReady && beadsTasks.length > 0) {
181→      // Register project with daemon
182→      await fetch('http://localhost:3456/api/projects', {
183→        method: 'POST',
184→        headers: { 'Content-Type': 'application/json' },
185→        body: JSON.stringify({ path: cwd })
186→      }).catch(() => {})
187→
188→      for (const task of beadsTasks) {
189→        try {
190→          // Map beads priority (0-4, 0=critical) to kspec priority (1-5, 1=highest)
191→          const beadsPriority = typeof task.priority === 'number' ? task.priority : 2
192→          const kspecPriority = Math.min(5, Math.max(1, beadsPriority + 1))
193→
194→          // Map beads type to kspec type
195→          const beadsType = String(task.issue_type ?? task.type ?? 'task')
196→          const kspecType = beadsType === 'feature' ? 'task' : (['bug', 'task', 'epic'].includes(beadsType) ? beadsType : 'task')
197→
198→          // Map beads status to kspec status
